type AccentTheme =
  | "warm-paper"
  | "cool-slate"
  | "forest-mist"
  | "brushed-silver"
  | "midnight-focus";
type ThemeMode = "full" | "highlight-only";
type ColorScheme = "light" | "dark" | "system";

const LEGACY_ACCENT_THEME_MAP: Record<string, AccentTheme> = {
  orange: "warm-paper",
  blue: "cool-slate",
  green: "forest-mist",
  purple: "brushed-silver"
};

function normalizeAccentTheme(theme: string | null | undefined): AccentTheme {
  if (!theme) {
    return "warm-paper";
  }

  if (theme in LEGACY_ACCENT_THEME_MAP) {
    return LEGACY_ACCENT_THEME_MAP[theme];
  }

  if (
    theme === "warm-paper" ||
    theme === "cool-slate" ||
    theme === "forest-mist" ||
    theme === "brushed-silver" ||
    theme === "midnight-focus"
  ) {
    return theme;
  }

  if (theme === "lavender-haze") {
    return "brushed-silver";
  }

  return "warm-paper";
}

