function getSenderInitials(sender: string) {
  const parts = sender
    .split(/\s+/)
    .map((part) => part.trim())
    .filter(Boolean);

  if (parts.length === 0) {
    return "?";
  }

  const first = parts[0]?.[0]?.toUpperCase() ?? "";
  const last = (parts.length > 1 ? parts[parts.length - 1] : parts[0])?.[0]?.toUpperCase() ?? "";
  return `${first}${last}`.slice(0, 2) || "?";
}

function stripHtml(html: string): string {
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, "")
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, "")
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<\/div>/gi, "\n")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function getAvatarColor(seed: string) {
  let hash = 0;

  for (const character of seed) {
    hash = character.charCodeAt(0) + ((hash << 5) - hash);
  }

  const hue = Math.abs(hash) % 360;
  return `hsl(${hue} 60% 46%)`;
}

function getPriorityAvatarPalette(seed: string) {
  const palette = [
    { background: "#22C55E", color: "#FFFFFF" },
    { background: "#4F46E5", color: "#FFFFFF" },
    { background: "#F97316", color: "#FFFFFF" },
    { background: "#DB2777", color: "#FFFFFF" },
    { background: "#0D9488", color: "#FFFFFF" },
    { background: "#7C3AED", color: "#FFFFFF" }
  ] as const;
  let hash = 0;
  for (const character of seed) {
    hash = character.charCodeAt(0) + ((hash << 5) - hash);
  }
  return palette[Math.abs(hash) % palette.length];
}

function renderSidebarCountBadge(
  value: number | null | undefined,
  options?: { emphasize?: boolean; dramatic?: boolean }
) {
  if (!value || value <= 0) {
    return null;
  }

  return (
    <span
      key={`unread-${value}`}
      className={`sidebar-count-badge ${
        value > 1 ? "sidebar-count-badge-pill" : "sidebar-count-badge-muted"
      } ${options?.emphasize ? "sidebar-count-badge-emphasis" : ""} ${
        options?.dramatic ? "sidebar-count-badge-dramatic" : ""
      } unread-badge`}
    >
      {value}
    </span>
  );
}

function displaySender(from: string): string {
  const match = from.match(/^(.+?)\s*</);

  if (match) {
    return match[1].trim();
  }

  return from.split("@")[0];
}

function displayFolderName(path: string) {
  return path.replace(/^INBOX\./i, "");
}

function formatSidebarAccountEmail(email: string | null | undefined) {
  if (!email) {
    return "No account";
  }

  const normalized = email.trim();
  const match = normalized.match(/^([^@\s]+)@([^@\s]+)$/);
  if (!match) {
    return normalized;
  }

  const username = match[1];
  const domain = match[2].toLowerCase();

  if (domain === "makingmyworldbetter.com") {
    return `${username}@MMWB`;
  }

  if (domain.endsWith(".com")) {
    return `${username}@${domain.slice(0, -4)}`;
  }

  return `${username}@${domain}`;
}

function formatSentRowRecipient(to: string[] | undefined): string {
  if (!to || to.length === 0) {
    return "No recipient";
  }

  const first = to[0];
  const nameMatch = first.match(/^(.+?)\s*</);
  const displayName = nameMatch
    ? nameMatch[1].trim()
    : first.includes("@")
      ? first.split("@")[0]
      : first.trim();

  if (to.length === 1) {
    return displayName;
  }

  return `${displayName}, +${to.length - 1} more`;
}

