  async function loadAiSettings() {
    setAiSettingsLoading(true);

    try {
      const settings = await getJson<AiSettingsSummary>("/api/ai/settings");
      setAiSettings(settings);
      if (settings.configured) {
        void loadAiAvailability();
      } else {
        setAiAvailabilitySummary(null);
      }
    } catch (error) {
      setAiSettingsError(
        error instanceof Error
          ? error.message
          : "Unable to load AI Writing Assistant settings."
      );
    } finally {
      setAiSettingsLoading(false);
    }
  }

  async function loadTavilySettings() {
    setTavilySettingsLoading(true);

    try {
      const settings = await getJson<TavilySettingsSummary>("/api/quickfact/settings");
      setTavilySettings(settings);
    } catch (error) {
      setTavilySettingsError(
        error instanceof Error
          ? error.message
          : "Unable to load QuickFact settings."
      );
    } finally {
      setTavilySettingsLoading(false);
    }
  }

  async function loadAiAvailability(force = false) {
    if (!force && isAiAvailabilityFresh(aiAvailabilitySummary)) {
      return aiAvailabilitySummary;
    }

    setAiAvailabilityLoading(true);

    try {
      const query = force ? "?force=1" : "";
      const summary = await getJson<AiAvailabilitySummary>(`/api/ai/availability${query}`);
      setAiAvailabilitySummary(summary);
      return summary;
    } catch (error) {
      const fallback: AiAvailabilitySummary = {
        ownerLabel: aiSettings?.ownerLabel ?? composeAiSettingsSummary?.ownerLabel ?? "Current owner",
        provider: "openai",
        configured: true,
        status: "unavailable_temporary_error",
        checkedAt: new Date().toISOString(),
        message:
          "Your API key is saved, but AI rewrites aren’t available right now. Update billing, limits, or retry later."
      };
      setAiAvailabilitySummary(fallback);
      return fallback;
    } finally {
      setAiAvailabilityLoading(false);
    }
  }

  async function saveAiSettingsKey() {
    const normalizedApiKey = aiApiKeyInput.trim();

    if (!normalizedApiKey) {
      setAiSettingsError("Paste an OpenAI API key to save it.");
      setAiSettingsSuccess(null);
      return;
    }

    setAiSettingsSaving(true);
    setAiSettingsError(null);
    setAiSettingsSuccess(null);

    try {
      const settings = await withTimeout(
        putJson<AiSettingsSummary>("/api/ai/settings", {
          apiKey: normalizedApiKey,
          validate: false
        }),
        7000,
        "Saving the OpenAI API key took too long. Try again."
      );
      setAiSettings(settings);
      setAiSettingsLastFour(normalizedApiKey.slice(-4).padStart(4, "0"));
      setAiApiKeyInput("");
      if (settings.configured) {
        void loadAiAvailability(true);
      } else {
        setAiAvailabilitySummary(null);
      }
      setAiSettingsSuccess("Saved.");
    } catch (error) {
      setAiSettingsError(
        error instanceof Error
          ? error.message
          : "Unable to save the OpenAI API key."
      );
    } finally {
      setAiSettingsSaving(false);
    }
  }

  async function testAiSettingsKey() {
    setAiSettingsTesting(true);
    setAiSettingsError(null);
    setAiSettingsSuccess(null);

    try {
      const settings = await withTimeout(
        postJson<AiSettingsSummary>("/api/ai/settings/test", {
          apiKey: aiApiKeyInput.trim() || undefined
        }),
        7000,
        "Testing the OpenAI API key took too long. Try again."
      );
      if (!aiApiKeyInput.trim()) {
        setAiSettings(settings);
        if (settings.configured) {
          void loadAiAvailability(true);
        } else {
          setAiAvailabilitySummary(null);
        }
      }
      if (settings.status === "connected") {
        setAiSettingsSuccess("Connected.");
      } else {
        setAiSettingsError(settings.lastError?.trim() || "Connection failed.");
      }
    } catch (error) {
      setAiSettingsError(
        error instanceof Error
          ? error.message
          : "Unable to validate the saved OpenAI API key."
      );
    } finally {
      setAiSettingsTesting(false);
    }
  }

